def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` class synced with the
    main dictionary.

    A decorator is used instead of a `UserDict` subclass to avoid a performance penalty on `Features` instantiation
    and to avoid breaking `isinstance(features, dict)` checks elsewhere in the code base.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper.__name__ = func.__name__
    return wrapper
